class TrieNB:
    def __init__(self):
        self.children = {}
        self.end = False
def longest_buildable_word(words):
    root = TrieNB()
    for w in words:
        node = root
        for ch in w:
            node = node.children.setdefault(ch, TrieNB())
        node.end = True
    best = ""
    def dfs(node, path):
        nonlocal best
        if path and not node.end:
            return
        if len(path) > len(best) or            (len(path) == len(best) and path < best):
            best = path
        for ch in sorted(node.children.keys()):
            dfs(node.children[ch], path + ch)
    dfs(root, "")
    return best

